5378	\begin{lemma}
5379	[Serre finiteness along a fibre]
5380	  \label{lem:sectionGradedModule_fg_fiber}
5381	  \leanok
5382	  \lean{AlgebraicGeometry.sectionGradedModule_fg_fiber}
5383	  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
5384	    lem:fiberModule_finitePresentation, def:sectionGradedRing,
5385	    def:sectionGradedModule}
5386	  Let \(\pi : X \to S\) be projective carrying \(L\), let \(F\) be finitely
5387	  presented, and let \(s \in S\).  Then the section graded ring \(R(X_s, L_s)\)
5388	  (\Cref{def:sectionGradedRing}) is Noetherian and the section graded module
5389	  \(M(X_s, F_s, L_s)\) (\Cref{def:sectionGradedModule}) is a finitely generated
5390	  \(R(X_s, L_s)\)-module.
5391	\end{lemma}
5392	
5393	\begin{proof}
5394	  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
5395	    lem:fiberModule_finitePresentation}
5396	  The fibre \(X_s\) is projective over the field \(\kappa(s)\) carrying \(L_s\)
5397	  (\Cref{lem:projective_with_fiber}), and \(F_s\) is coherent
5398	  (\Cref{lem:fiberModule_finitePresentation}); apply
5399	  \Cref{lem:sectionGradedModule_fg} on \(X_s\), retaining its first two
5400	  conclusions.
5401	\end{proof}
