5403	\begin{lemma}
5404	[The graded Hilbert function is a genuine dimension on projective fibres]
5405	  \label{lem:hilbertFunction_finiteDimensional}
5406	  \leanok
5407	  \lean{AlgebraicGeometry.hilbertFunction_finiteDimensional}
5408	  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
5409	    lem:fiberModule_finitePresentation, def:hilbert_polynomial}
5410	  Let \(\pi : X \to S\) be projective carrying \(L\), let \(F\) be finitely
5411	  presented, and let \(s \in S\).  Then for every \(m\) the space of global
5412	  sections \(\Gamma(X_s, F_s \otimes L_s^{\otimes m})\) is a finite-dimensional
5413	  \(\kappa(s)\)-vector space.  In particular the graded Hilbert function
5414	  \(m \mapsto \dim_{\kappa(s)} \Gamma(X_s, F_s \otimes L_s^{\otimes m})\)
5415	  (\Cref{def:hilbert_polynomial}) takes finite values, so it is not the
5416	  \(\operatorname{finrank}\) junk value at any \(m\).
5417	\end{lemma}
5418	
5419	\begin{proof}
5420	  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
5421	    lem:fiberModule_finitePresentation}
5422	  This is the third conclusion of \Cref{lem:sectionGradedModule_fg} applied on
5423	  the fibre \(X_s\), which is projective over \(\kappa(s)\) carrying \(L_s\)
5424	  (\Cref{lem:projective_with_fiber}) with \(F_s\) coherent
5425	  (\Cref{lem:fiberModule_finitePresentation}): finite dimensionality over the
5426	  residue field of each graded component
5427	  \(\Gamma(X_s, F_s \otimes L_s^{\otimes m})\).
5428	\end{proof}
