5430	\subsection{The graded Hilbert--Serre bridge}
5431	\label{subsec:graded_hilbert_bridge}
5432	
5433	The rationality engine \Cref{lem:gradedHilbertSerre_rational} consumes an
5434	abstract finitely generated \(\mathbb{N}\)-graded \(\kappa\)-vector space
5435	carrying \(r\) commuting degree-one endomorphisms.  We record its input as a
5436	package \(\mathrm{GradedHilbert}\), factor Serre finiteness in this engine-ready
5437	form as a single leaf (\Cref{lem:gradedHilbert_fiber}, a companion to
5438	\Cref{lem:sectionGradedModule_fg}), and derive the rationality of the fibre
5439	graded Hilbert function --- hence the genuineness of the Hilbert polynomial
5440	(\Cref{def:hilbert_polynomial}) --- as sorry-free glue.  This is the
5441	\(\mathrm{DirectSum}\)-decomposition bridge of inbox \texttt{I-0109}.
5442	
5443	\begin{definition}
5444	[Engine-ready packaging of a Hilbert function]
5445	  \label{def:gradedHilbert}
5446	  \leanok
5447	  \lean{AlgebraicGeometry.GradedHilbert}
5448	  \uses{lem:gradedHilbertSerre_rational, def:ratHilb}
5449	  Fix a field \(\kappa\) and a function \(f : \mathbb{N} \to \mathbb{N}\).  A
5450	  \(\mathrm{GradedHilbert}\) datum for \((\kappa, f)\) is a natural number \(r\),
5451	  an \(\mathbb{N}\)-graded \(\kappa\)-vector space \(M = \bigoplus_n M_n\) (an
5452	  internal grading \(\mathcal{M} : \mathbb{N} \to \mathrm{Submodule}_\kappa M\)
5453	  with \(\mathrm{DirectSum.Decomposition}\)) whose graded pieces \(M_n\) are all
5454	  finite-dimensional, together with \(r\) pairwise-commuting \(\kappa\)-linear
5455	  endomorphisms \(g_0, \dots, g_{r-1}\) that each raise the grading degree by one,
5456	  such that \(\dim_\kappa M_n = f(n)\) for all \(n\) and \(M\) is a finite module
5457	  over the polynomial ring \(\kappa[X_0, \dots, X_{r-1}]\) acting through the
5458	  \(g_i\).  This bundles exactly the data and hypotheses consumed by the graded
5459	  Hilbert--Serre rationality engine \Cref{lem:gradedHilbertSerre_rational}.
5460	\end{definition}
5461	
5462	\begin{lemma}
5463	[Rationality from a \(\mathrm{GradedHilbert}\) datum]
5464	  \label{lem:gradedHilbert_isRatHilb}
5465	  \leanok
5466	  \lean{AlgebraicGeometry.GradedHilbert.isRatHilb}
5467	  \uses{def:gradedHilbert, lem:gradedHilbertSerre_rational, def:ratHilb}
5468	  If \((\kappa, f)\) admits a \(\mathrm{GradedHilbert}\) datum of order \(r\)
5469	  (\Cref{def:gradedHilbert}), then \(f\) is a rational Hilbert function of order
5470	  \(r\) (\Cref{def:ratHilb}): there are \(p \in \mathbb{Q}[X]\) and \(N\) with
5471	  \(f(n) = [X^n]\bigl(p \cdot (1-X)^{-r}\bigr)\) for all \(n > N\).
5472	\end{lemma}
5473	
5474	\begin{proof}
5475	  \leanok
5476	  \uses{lem:gradedHilbertSerre_rational}
5477	  Apply the graded Hilbert--Serre rationality engine
5478	  (\Cref{lem:gradedHilbertSerre_rational}) to the graded module \(M\), its
5479	  grading \(\mathcal{M}\), and the degree-one generators \(g_i\) of the datum;
5480	  its hypotheses (finite-dimensional components, finiteness over
5481	  \(\kappa[X_0,\dots,X_{r-1}]\)) are the datum's fields.  This yields that
5482	  \(n \mapsto \dim_\kappa M_n\) is a rational Hilbert function of order \(r\), and
5483	  \(\dim_\kappa M_n = f(n)\) identifies it with \(f\).
5484	\end{proof}
5485	
5486	\begin{lemma}
5487	[Serre finiteness in engine-ready form]
5488	  \label{lem:gradedHilbert_fiber}
5489	  \lean{AlgebraicGeometry.gradedHilbert_fiber}
5490	  \leanok
5491	  \uses{def:gradedHilbert, lem:sectionGradedModule_fg, lem:projective_with_fiber,
5492	    def:projective_with, def:hilbert_polynomial}
5493	  \source{nitsure-hilbert-quot}
5494	  \textit{Source: [Nitsure], \S 1 (FGA Explained Ch.~5); Serre's theorem, as in
5495	  \Cref{lem:sectionGradedModule_fg}.}
5496	  Let \(\pi : X \to S\) be projective carrying the very ample line bundle \(L\),
5497	  let \(F\) be finitely presented, and let \(s \in S\).  Then the graded Hilbert
5498	  function \(m \mapsto \dim_{\kappa(s)} \Gamma(X_s, F_s \otimes L_s^{\otimes m})\)
5499	  (\Cref{def:hilbert_polynomial}) admits a \(\mathrm{GradedHilbert}\) datum over
5500	  the residue field \(\kappa(s)\) (\Cref{def:gradedHilbert}).
5501	
5502	  \emph{Status.} This is \Cref{lem:sectionGradedModule_fg} (Serre) restated in
5503	  engine-ready form; its Lean statement is a named leaf.  Taking \(M\) to be the
5504	  fibre section module \(M(X_s, F_s, L_s)\) and the \(d+1\) generators to be the
5505	  homogeneous coordinate sections of the very ample embedding
5506	  \(X_s \hookrightarrow \mathbb{P}^d_{\kappa(s)}\), the content is the finite
5507	  generation of \(M(X_s, F_s, L_s)\) over the homogeneous coordinate ring
5508	  \(\kappa(s)[x_0, \dots, x_d]\) --- the finiteness of
5509	  \Cref{lem:sectionGradedModule_fg} together with the degree-one coordinate
5510	  action.
5511	\end{lemma}
5512	
5513	\begin{proof}
5514	  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber, def:projective_with}
5515	  The fibre \(X_s\) is projective over \(\kappa(s)\) carrying \(L_s\)
5516	  (\Cref{lem:projective_with_fiber}), so it admits a closed immersion
5517	  \(i : X_s \hookrightarrow \mathbb{P}^d_{\kappa(s)}\) with
5518	  \(L_s \cong i^*\mathcal{O}(1)\), and \(F_s\) is coherent.  By Serre
5519	  (\Cref{lem:sectionGradedModule_fg}) the section module \(M(X_s, F_s, L_s)\) is
5520	  a finitely generated graded module over \(R(X_s, L_s)\) with
5521	  finite-dimensional components.  The homogeneous coordinates \(x_0, \dots, x_d\)
5522	  restrict along \(i\) to \(d+1\) sections of \(L_s\) generating \(R(X_s, L_s)\)
5523	  in large degrees, so \(M(X_s, F_s, L_s)\) is finite over the polynomial ring
5524	  \(\kappa(s)[x_0, \dots, x_d]\), with \(x_j\) acting by multiplication (raising
5525	  degree by one).  Its \(m\)-th graded piece \(\Gamma(X_s, F_s \otimes
5526	  L_s^{\otimes m})\) has \(\kappa(s)\)-dimension the graded Hilbert function, so
5527	  this data is a \(\mathrm{GradedHilbert}\) datum.
5528	\end{proof}
5529	
5530	\begin{lemma}
5531	[Rationality of the fibre graded Hilbert function]
5532	  \label{lem:hilbertFunction_isRatHilb}
5533	  \lean{AlgebraicGeometry.hilbertFunction_isRatHilb}
5534	  \leanok
5535	  \uses{lem:gradedHilbert_fiber, lem:gradedHilbert_isRatHilb, def:ratHilb}
5536	  Let \(\pi : X \to S\) be projective carrying \(L\), let \(F\) be finitely
5537	  presented, and let \(s \in S\).  Then the graded Hilbert function
5538	  \(m \mapsto \dim_{\kappa(s)} \Gamma(X_s, F_s \otimes L_s^{\otimes m})\) is a
5539	  rational Hilbert function of some order \(d\) (\Cref{def:ratHilb}).
5540	\end{lemma}
5541	
5542	\begin{proof}
5543	  \uses{lem:gradedHilbert_fiber, lem:gradedHilbert_isRatHilb}
5544	  By \Cref{lem:gradedHilbert_fiber} the graded Hilbert function admits a
5545	  \(\mathrm{GradedHilbert}\) datum over \(\kappa(s)\); apply
5546	  \Cref{lem:gradedHilbert_isRatHilb}.
5547	\end{proof}
5548	
5549	\begin{lemma}
5550	[The Hilbert polynomial computes the Hilbert function on projective fibres]
5551	  \label{lem:hilbertPolynomial_eval_eventually_of_projective}
5552	  \lean{AlgebraicGeometry.hilbertPolynomial_eval_eventually_of_projective}
5553	  \leanok
5554	  \uses{lem:hilbertFunction_isRatHilb, cor:hilbertPolynomial_eval_of_isRatHilb,
5555	    def:hilbert_polynomial}
5556	  Let \(S\) be locally Noetherian, let \(\pi : X \to S\) be projective carrying
5557	  \(L\) and locally of finite type, let \(F\) be finitely presented, and let
5558	  \(s \in S\).  Then for all \(m \gg 0\) the Hilbert polynomial of
5559	  \Cref{def:hilbert_polynomial} satisfies
5560	  \[
5561	    \Phi_{F,s}(m) \;=\; \dim_{\kappa(s)}
5562	      \Gamma\bigl(X_s,\, F_s \otimes L_s^{\otimes m}\bigr).
5563	  \]
5564	  This is the projective-fibre realisation of
5565	  \Cref{thm:hilbertPoly_of_sectionModule}: it is the point at which
5566	  \(\Phi_{F,s}\) ceases to be a formal choice and becomes the genuine
5567	  Snapper/Hilbert polynomial of the fibre.
5568	\end{lemma}
5569	
5570	\begin{proof}
5571	  \uses{lem:hilbertFunction_isRatHilb, cor:hilbertPolynomial_eval_of_isRatHilb}
5572	  By \Cref{lem:hilbertFunction_isRatHilb} the graded Hilbert function is a
5573	  rational Hilbert function of some order \(d\); conclude by the
5574	  polynomial-extraction corollary
5575	  \Cref{cor:hilbertPolynomial_eval_of_isRatHilb}.
5576	\end{proof}
